import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera } from '@react-three/drei';
import { useLocation, useNavigate } from 'react-router-dom';
import * as THREE from 'three';

const SmallCube = ({ position, colors, initialPosition, isAnimating, currentRotation }) => {
  const meshRef = useRef();
  const [rotationAngle, setRotationAngle] = useState(0);
  
  useFrame(() => {
    if (isAnimating && meshRef.current) {
      setRotationAngle(prev => Math.min(prev + 0.1, Math.PI / 2));
    }
  });

  const createMaterial = (color) => color ? new THREE.MeshStandardMaterial({ color }) : null;

  const materials = [
    createMaterial(colors.right),
    createMaterial(colors.left),
    createMaterial(colors.up),
    createMaterial(colors.down),
    createMaterial(colors.front),
    createMaterial(colors.back),
  ];

  let rotation = [0, 0, 0];
  let positionOffset = [0, 0, 0];
  
  if (isAnimating && currentRotation) {
    const { axis, affectedPositions } = currentRotation;
    const isAffected = affectedPositions.some(pos =>
      pos[0] === initialPosition[0] &&
      pos[1] === initialPosition[1] &&
      pos[2] === initialPosition[2]
    );

    if (isAffected) {
      if (axis === 'y') rotation[1] = rotationAngle;
      if (axis === 'x') rotation[0] = rotationAngle;
      if (axis === 'z') rotation[2] = rotationAngle;
    }
  }

  return (
    <mesh ref={meshRef} position={initialPosition} rotation={rotation}>
      <boxGeometry args={[0.96, 0.96, 0.96]} />
      {materials.map((mat, i) => mat && <meshStandardMaterial key={i} attach={`material-${i}`} {...mat} />)}
    </mesh>
  );
};

const RubiksCube = ({ solutionMoves, isPlaying, currentMoveIndex: externalMoveIndex, onMoveComplete, onAnimationComplete, initialCubeState }) => {

  const [cubeState, setCubeState] = useState(initialCubeState);

  const colorMap = {
    white: '#ffffff',
    yellow: '#ffff00',
    orange: '#ffa500',
    red: '#ff0000',
    green: '#00ff00',
    blue: '#0000ff'
  };

  const parseMoves = (moveString) => moveString ? moveString.trim().split(/\s+/) : [];
  const moves = parseMoves(solutionMoves);

  const getStickerIndex = (x, y, z, face) => {
    // ✅ FIXED CORRECT STANDARD ORIENTATION
    if (face === 'U') return (1 - z) * 3 + (x + 1);
    if (face === 'D') return (z + 1) * 3 + (x + 1);
    if (face === 'F') return (1 - y) * 3 + (x + 1);
    if (face === 'B') return (1 - y) * 3 + (1 - x);
    if (face === 'L') return (1 - y) * 3 + (z + 1);
    if (face === 'R') return (1 - y) * 3 + (1 - z);
    return 4;
  };

  const getColors = (x, y, z) => ({
    right: x === 1 ? colorMap[cubeState.R[getStickerIndex(x, y, z, 'R')]] : null,
    left: x === -1 ? colorMap[cubeState.L[getStickerIndex(x, y, z, 'L')]] : null,
    up: y === 1 ? colorMap[cubeState.U[getStickerIndex(x, y, z, 'U')]] : null,
    down: y === -1 ? colorMap[cubeState.D[getStickerIndex(x, y, z, 'D')]] : null,
    front: z === 1 ? colorMap[cubeState.F[getStickerIndex(x, y, z, 'F')]] : null,
    back: z === -1 ? colorMap[cubeState.B[getStickerIndex(x, y, z, 'B')]] : null,
  });

  const positions = [];
  for (let x = -1; x <= 1; x++) {
    for (let y = -1; y <= 1; y++) {
      for (let z = -1; z <= 1; z++) {
        positions.push({ x, y, z });
      }
    }
  }

  return (
    <group>
      {positions.map((pos, idx) => {
        const colors = getColors(pos.x, pos.y, pos.z);
        if (!Object.values(colors).some(c => c)) return null;

        return (
          <SmallCube
            key={idx}
            initialPosition={[pos.x, pos.y, pos.z]}
            colors={colors}
            isAnimating={false}
            currentRotation={null}
          />
        );
      })}
    </group>
  );
};

const Cube3D = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { solution, cubeState } = location.state;

  return (
    <div>
      <button onClick={() => navigate('/input')}>← Back</button>

      <Canvas style={{ height: '500px' }}>
        <PerspectiveCamera makeDefault position={[4, 3, 5]} />
        <OrbitControls />
        <ambientLight />
        <RubiksCube initialCubeState={cubeState} />
      </Canvas>

      <p>{solution}</p>
    </div>
  );
};

export default Cube3D;
